Here's the proper approach using MAUI's `Window` lifecycle events and `Preferences`:

**In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "NoteDraft";

    public NotePage()
    {
        InitializeComponent();
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();

        // Restore draft
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);

        // Subscribe to lifecycle events
        var window = Application.Current?.Windows.FirstOrDefault();
        if (window != null)
        {
            window.Backgrounding += OnBackgrounding;
            window.Resumed += OnResumed;
        }
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();

        var window = Application.Current?.Windows.FirstOrDefault();
        if (window != null)
        {
            window.Backgrounding -= OnBackgrounding;
            window.Resumed -= OnResumed;
        }
    }

    private void OnBackgrounding(object? sender, BackgroundingEventArgs e)
    {
        // Save draft when app goes to background
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnResumed(object? sender, EventArgs e)
    {
        // Restore draft when app returns
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    public void ClearDraft()
    {
        // Call this after the user explicitly saves/discards
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- **`Window.Backgrounding`** fires when the app is sent to the background — save here
- **`Window.Resumed`** fires when the app returns to the foreground — restore here
- **`Preferences`** is a simple key-value store that persists across sessions (backed by `SharedPreferences` on Android, `NSUserDefaults` on iOS)
- Always **unsubscribe** in `OnDisappearing` to avoid leaks
- Call `ClearDraft()` after the user intentionally saves or discards the note

For larger drafts, consider `SecureStorage` or writing to `FileSystem.AppDataDirectory` instead of `Preferences`.
